const { withGradleProperties } = require('expo/config-plugins');

// Release builds exhaust the default Gradle daemon memory
// (-Xmx2048m -XX:MaxMetaspaceSize=512m): lintVitalAnalyzeRelease dies with
// a Metaspace OOM. android/ is regenerated by prebuild, so the raised limits
// must live here rather than in android/gradle.properties.
const JVM_ARGS_PROPERTY = {
  type: 'property',
  key: 'org.gradle.jvmargs',
  value: '-Xmx4096m -XX:MaxMetaspaceSize=1024m',
};

module.exports = function withGradleJvmArgs(config) {
  return withGradleProperties(config, (config) => {
    config.modResults = config.modResults.filter(
      (item) => !(item.type === 'property' && item.key === JVM_ARGS_PROPERTY.key)
    );
    config.modResults.push(JVM_ARGS_PROPERTY);
    return config;
  });
};
